import type { User } from '../../models/User';
import { UserRole } from '../../models/User';
import { authEndpoint } from './endpoint';

/**
 * Unified auth service.
 */
export const authService = {
  login: (username: string, password: string, activeCompanyId?: string) =>
    authEndpoint.login({ id: username, password, activeCompanyId }),

  logout: () => authEndpoint.logout(),

  getCurrentUser: () => authEndpoint.getProfile(),

  /** Utility: check for exact role */
  hasRole: (user: User | null, role: UserRole): boolean =>
    user?.role === role,

  /** Utility: check for any of the given roles */
  hasAnyRole: (user: User | null, roles: UserRole[]): boolean =>
    user ? roles.includes(user.role) : false,

  /** Utility: true for Manager or Admin */
  isManagerOrAdmin: (user: User | null): boolean =>
    user ? [UserRole.Manager, UserRole.Admin].includes(user.role) : false,

  /** POST /auth/switch-company — admin only */
  switchCompany: (companyId: string) => authEndpoint.switchCompany(companyId),
};
