import { apiClient } from '../api';
import type { User } from '../../models/User';
import type { AuthLoginResponse, AuthUserInfo, LoginResponse } from './responseModel';
import type { LoginRequest, ChangePasswordRequest, UpdateProfileRequest } from './requestModel';
import { mapAuthUser, mapLoginResponse } from './mapper';

/**
 * Real API calls to WebApp BFF auth endpoints.
 * All routes are relative to VITE_API_URL (web-bff/api/v1).
 *
 * BFF routes:
 *   POST /auth/login            [AllowAnonymous]
 *   POST /auth/refresh-token    [AllowAnonymous]
 *   POST /auth/logout
 *   GET  /auth/profile
 *   PUT  /auth/profile
 *   POST /auth/change-password
 */
export const authEndpoint = {
  /** POST /auth/login → JWT access token + user */
  login: (req: LoginRequest): Promise<LoginResponse> =>
    apiClient
      .post<AuthLoginResponse>('/auth/login', req)
      .then(mapLoginResponse),

  /** POST /auth/logout */
  logout: (): Promise<void> => apiClient.post<void>('/auth/logout'),

  /** POST /auth/refresh-token → new access token */
  refreshToken: (refreshToken: string): Promise<LoginResponse> =>
    apiClient
      .post<AuthLoginResponse>('/auth/refresh-token', { refreshToken })
      .then(mapLoginResponse),

  /** GET /auth/profile → current user */
  getProfile: (): Promise<User> =>
    apiClient.get<AuthUserInfo>('/auth/profile').then(mapAuthUser),

  /** PUT /auth/profile → updated user */
  updateProfile: (data: UpdateProfileRequest): Promise<User> =>
    apiClient.put<AuthUserInfo>('/auth/profile', data).then(mapAuthUser),

  /** POST /auth/change-password */
  changePassword: (data: ChangePasswordRequest): Promise<void> =>
    apiClient.post<void>('/auth/change-password', data),

  /** POST /auth/switch-company → new JWT with updated company_id claim (admin only) */
  switchCompany: (companyId: string): Promise<LoginResponse> =>
    apiClient
      .post<AuthLoginResponse>('/auth/switch-company', { companyId })
      .then(mapLoginResponse),
};
